from __future__ import annotations

import functools
import socket
import ssl
import typing

from .._exceptions import (
    ConnectError,
    ConnectTimeout,
    ExceptionMapping,
    ReadError,
    ReadTimeout,
    WriteError,
    WriteTimeout,
    map_exceptions,
)
from .._utils import is_socket_readable
from .base import SOCKET_OPTION, NetworkBackend, NetworkStream


class TLSinTLSStream(NetworkStream):  # pragma: no cover
    """
    A stream wrapper that layers an SSLObject on top of an existing socket.

    This is required when performing TLS-over-TLS: the standard
    SSLContext.wrap_socket cannot wrap an SSLSocket, so an SSLObject
    backed by MemoryBIOs is used to implement the TLS layer.
    """

    # Defined in RFC 8449
    TLS_RECORD_SIZE = 16384

    def __init__(
        self,
        sock: socket.socket,
        ssl_context: ssl.SSLContext,
        server_hostname: str | None = None,
        timeout: float | None = None,
    ):
        """Create a TLS-over-TLS stream using MemoryBIO-backed SSLObject.

        sock: an underlying connected socket (may already be SSL-wrapped).
        ssl_context: SSLContext to use for the new TLS layer.
        server_hostname: optional TLS server hostname for SNI.
        timeout: socket timeout used during the TLS handshake.
        """
        self._sock = sock
        self._incoming = ssl.MemoryBIO()
        self._outgoing = ssl.MemoryBIO()

        self.ssl_obj = ssl_context.wrap_bio(
            incoming=self._incoming,
            outgoing=self._outgoing,
            server_hostname=server_hostname,
        )

        self._sock.settimeout(timeout)
        self._perform_io(self.ssl_obj.do_handshake)

    def _perform_io(
        self,
        func: typing.Callable[..., typing.Any],
    ) -> typing.Any:
        """Drive the SSLObject I/O until the operation completes.

        func: a callable that operates on self.ssl_obj (e.g. do_handshake,
              read, write). This method handles SSLWantRead/Write and
        exchanges data with the underlying socket as needed.
        """
        ret = None

        while True:
            errno = None
            try:
                ret = func()
            except (ssl.SSLWantReadError, ssl.SSLWantWriteError) as e:
                errno = e.errno

            # Send any data produced by the SSLObject.
            try:
                out = self._outgoing.read()
            except ssl.SSLEOFError:
                out = b""
            if out:
                self._sock.sendall(out)

            # If SSLObject asked for more data to read from the socket, read it.
            if errno == ssl.SSL_ERROR_WANT_READ:
                buf = self._sock.recv(self.TLS_RECORD_SIZE)

                if buf:
                    self._incoming.write(buf)
                else:
                    # Remote side closed the underlying socket.
                    self._incoming.write_eof()
            if errno is None:
                return ret

    def read(self, max_bytes: int, timeout: float | None = None) -> bytes:
        """Read up to max_bytes of application data from the TLS layer.

        timeout is applied to the underlying socket operations.
        """
        exc_map: ExceptionMapping = {socket.timeout: ReadTimeout, OSError: ReadError}
        with map_exceptions(exc_map):
            self._sock.settimeout(timeout)
            return typing.cast(
                bytes, self._perform_io(functools.partial(self.ssl_obj.read, max_bytes))
            )

    def write(self, buffer: bytes, timeout: float | None = None) -> None:
        """Write the given bytes through the TLS layer, respecting timeout."""
        exc_map: ExceptionMapping = {socket.timeout: WriteTimeout, OSError: WriteError}
        with map_exceptions(exc_map):
            self._sock.settimeout(timeout)
            while buffer:
                nsent = self._perform_io(functools.partial(self.ssl_obj.write, buffer))
                buffer = buffer[nsent:]

    def close(self) -> None:
        """Close the underlying socket."""
        self._sock.close()

    def start_tls(
        self,
        ssl_context: ssl.SSLContext,
        server_hostname: str | None = None,
        timeout: float | None = None,
    ) -> NetworkStream:
        """Starting TLS on an already TLS-over-TLS stream is not supported here."""
        raise NotImplementedError()

    def get_extra_info(self, info: str) -> typing.Any:
        """Return extra information about the stream (ssl_object, addresses, socket)."""
        if info == "ssl_object":
            return self.ssl_obj
        if info == "client_addr":
            return self._sock.getsockname()
        if info == "server_addr":
            return self._sock.getpeername()
        if info == "socket":
            return self._sock
        if info == "is_readable":
            return is_socket_readable(self._sock)
        return None


class SyncStream(NetworkStream):
    def __init__(self, sock: socket.socket) -> None:
        """A synchronous stream wrapper around a plain socket object."""
        self._sock = sock

    def read(self, max_bytes: int, timeout: float | None = None) -> bytes:
        """Read up to max_bytes bytes from the underlying socket with an optional timeout."""
        exc_map: ExceptionMapping = {socket.timeout: ReadTimeout, OSError: ReadError}
        with map_exceptions(exc_map):
            self._sock.settimeout(timeout)
            return self._sock.recv(max_bytes)

    def write(self, buffer: bytes, timeout: float | None = None) -> None:
        """Write the entire buffer to the underlying socket with an optional timeout."""
        if not buffer:
            return

        exc_map: ExceptionMapping = {socket.timeout: WriteTimeout, OSError: WriteError}
        with map_exceptions(exc_map):
            self._sock.settimeout(timeout)
            self._sock.sendall(buffer)

    def close(self) -> None:
        """Close the underlying socket cleanly."""
        self._sock.close()

    def start_tls(
        self,
        ssl_context: ssl.SSLContext,
        server_hostname: str | None = None,
        timeout: float | None = None,
    ) -> NetworkStream:
        """Upgrade the existing plain socket to a TLS-protected stream.

        If the underlying socket is already an SSLSocket, use a MemoryBIO-based
        SSLObject to layer TLS over TLS. Otherwise wrap the socket with
        ssl_context.wrap_socket and return a new SyncStream for the wrapped socket.
        """
        # Ensure the socket uses the requested timeout during handshake.
        self._sock.settimeout(timeout)
        # If socket is already SSLSocket, use TLS-in-TLS implementation.
        if isinstance(self._sock, ssl.SSLSocket):
            return TLSinTLSStream(self._sock, ssl_context, server_hostname, timeout)
        # Otherwise, wrap the socket directly. wrap_socket will perform the handshake.
        wrapped = ssl_context.wrap_socket(self._sock, server_hostname=server_hostname)
        # Ensure the wrapped socket retains the timeout setting
        wrapped.settimeout(timeout)
        return SyncStream(wrapped)

    def get_extra_info(self, info: str) -> typing.Any:
        """Return extra information about the underlying socket or TLS layer."""
        if info == "ssl_object":
            # If this is an SSLSocket, return its SSLObject via ._sslobj if present
            if isinstance(self._sock, ssl.SSLSocket):
                return getattr(self._sock, "unwrap", None) and getattr(self._sock, "cipher", None) and getattr(self._sock, "_sslobj", None)
            return None
        if info == "client_addr":
            return self._sock.getsockname()
        if info == "server_addr":
            try:
                return self._sock.getpeername()
            except OSError:
                return None
        if info == "socket":
            return self._sock
        if info == "is_readable":
            return is_socket_readable(self._sock)
        return None


class SyncNetworkBackend(NetworkBackend):
    def __init__(self) -> None:
        """Synchronous network backend using the standard socket module."""
        super().__init__()

    def connect_tcp(
        self,
        host: str,
        port: int,
        timeout: float | None = None,
        local_address: tuple[str, int] | None = None,
        socket_options: typing.Iterable[SOCKET_OPTION] | None = None,
    ) -> NetworkStream:
        """Connect to a TCP host:port and return a connected NetworkStream.

        socket_options is an iterable of tuples to pass to setsockopt.
        local_address is an optional (host, port) to bind before connect.
        """
        exc_map: ExceptionMapping = {socket.timeout: ConnectTimeout, OSError: ConnectError}
        err: typing.Optional[BaseException] = None
        # Resolve addresses and try them
        infos = socket.getaddrinfo(host, port, type=socket.SOCK_STREAM)
        with map_exceptions(exc_map):
            for family, socktype, proto, _, sockaddr in infos:
                sock: typing.Optional[socket.socket] = None
                try:
                    sock = socket.socket(family, socktype, proto)
                    # Apply socket options if any
                    if socket_options:
                        for opt in socket_options:
                            try:
                                sock.setsockopt(*opt)
                            except Exception:
                                # ignore individual option failures
                                pass
                    if local_address:
                        sock.bind(local_address)
                    sock.settimeout(timeout)
                    sock.connect(sockaddr)
                    return SyncStream(sock)
                except Exception as e:
                    err = e
                    if sock is not None:
                        try:
                            sock.close()
                        except Exception:
                            pass
                    # try next address
                    continue
            # If we reach here, all attempts failed; map_exceptions will handle raising proper error
            if err is not None:
                raise err
            raise ConnectError("Unable to connect")

    def connect_unix_socket(
        self,
        path: str,
        timeout: float | None = None,
        socket_options: typing.Iterable[SOCKET_OPTION] | None = None,
    ) -> NetworkStream:
        """Connect to a UNIX domain socket at the given path and return a NetworkStream."""
        exc_map: ExceptionMapping = {socket.timeout: ConnectTimeout, OSError: ConnectError}
        with map_exceptions(exc_map):
            sock = socket.socket(socket.AF_UNIX, socket.SOCK_STREAM)
            try:
                if socket_options:
                    for opt in socket_options:
                        try:
                            sock.setsockopt(*opt)
                        except Exception:
                            pass
                sock.settimeout(timeout)
                sock.connect(path)
                return SyncStream(sock)
            except Exception:
                try:
                    sock.close()
                except Exception:
                    pass
                raise